export const blogPosts: BlogPost[] = [
  ...existingBlogPosts,
  ...scheduledBlogPosts,
];

function publishDateToUtc(dateString: string): number {
  const value = Date.parse(`${dateString}T00:00:00.000Z`);
  return Number.isNaN(value) ? 0 : value;
}

export function isBlogPostPublished(post: BlogPost, now: Date = new Date()) {
  const dateString = post.publishDate ?? post.date;
  return publishDateToUtc(dateString) <= now.getTime();
}

export function getPublishedBlogPosts(now: Date = new Date()) {
  return blogPosts.filter((post) => isBlogPostPublished(post, now));
}

export function getBlogPost(slug?: string, options: { includeUnpublished?: boolean } = {}) {
  const post = blogPosts.find((candidate) => candidate.slug === slug);
  if (!post) return undefined;
  if (options.includeUnpublished || isBlogPostPublished(post)) return post;
  return undefined;
}


